import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAppContext } from '../context/AppContext';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAppContext();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const result = await login(email, password);
      if (result.success) {
        // Store business ID in localStorage
        const businessId = result.data?.business?.id || result.data?.data?.business?.id;
        if (businessId) {
          localStorage.setItem('businessId', businessId);
          console.log('✅ Business ID stored:', businessId);
        }
        
        // Also store user data
        const userData = result.data?.business || result.data?.data?.business;
        if (userData) {
          localStorage.setItem('user', JSON.stringify(userData));
        }
        
        navigate('/dashboard');
        toast.success('Welcome back!');
      }
    } catch (error) {
      toast.error(error.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  // Demo login for testing
  const handleDemoLogin = () => {
    setEmail('demo@example.com');
    setPassword('password123');
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <h1>AI Customer Support</h1>
          <p>Sign in to your account</p>
        </div>
        
        <form onSubmit={handleSubmit} className="login-form">
          <div className="form-group">
            <label>Email Address</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
            />
          </div>
          
          <div className="form-group">
            <label>Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
            />
          </div>
          
          <button type="submit" className="btn-primary" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
          
          <button 
            type="button" 
            className="btn-secondary demo-btn" 
            onClick={handleDemoLogin}
          >
            Use Demo Credentials
          </button>
        </form>
        
        <div className="login-footer">
          <p>Demo: demo@example.com / password123</p>
        </div>
      </div>
    </div>
  );
};

// Make sure this export is present
export default LoginPage;
